$.ajaxSetup({
    headers: {
        "X-CSRF-TOKEN": $('meta[name="csrf-token"]').attr("content"),
    },
});

$(function () {
    
    // Add User
    $(document).on("submit", "#formAddUser", function (e) {
        e.preventDefault();
        let form = $(this);
        $.ajax({
            url: form.attr("action"),
            type: "POST",
            data: form.serialize(),
            success: function (res) {
                if (res.success) {
                    $("#modalAddUser").modal("hide");
                    $("#tableUserList").DataTable().ajax.reload();
                    Swal.fire("Sukses", res.message, "success");
                }
            },
            error: function (xhr) {
                Swal.fire(
                    "Error",
                    xhr.responseJSON?.message || "Terjadi kesalahan",
                    "error"
                );
            },
        });
    });


    // Update User
    $(document).on("submit", "#formEditUser", function (e) {
        e.preventDefault();
        let form = $(this);

        $.ajax({
            url: form.attr("action"),
            type: "POST", // tetap pakai POST karena ada _method PUT
            data: form.serialize(),
            success: function (res) {
                if (res.success) {
                    $("#modalEditUser").modal("hide");
                    $("#tableUserList").DataTable().ajax.reload();
                    Swal.fire("Sukses", res.message, "success");
                }
            },
            error: function (xhr) {
                Swal.fire(
                    "Error",
                    xhr.responseJSON.message || "Terjadi kesalahan",
                    "error"
                );
            },
        });
    });
    
    $(document).on(
        "click",
        '#tableUserList button[data-target="#modalEditUser"]',
        function () {
            let id = $(this).data("id");
            let url = window.routes.getUser.replace(":id", id);

            $.get(url, function (res) {
                let user = res.user;
                $("#formEditUser").attr("action", url);
                $("#edit_name").val(user.name);
                $("#edit_email").val(user.email);
                $("#edit_aktifasi").val(user.active ? "Aktif" : "Nonaktif");
                $("#edit_akses").val(user.role || "Aktif");
                $("#edit_password, #edit_password_confirmation").val("");
                $("#modalEdit").modal("show");
            });
        }
    );
});